// ─── INGREDIENT CATEGORY CLASSIFIER ─────────────────────────────────────────
function categorize(name) {
  const n = name.toLowerCase();
  // Petit-déjeuner — priorité haute
  if (/haferflocken|dattel|eau minérale/.test(n)) return "🌅 Petit-Déjeuner & Collation";
  if (/amande|mignonette chocolat/.test(n)) return "🌅 Petit-Déjeuner & Collation";
  // Spécifiques overrides
  if (/haricot rouge/.test(n)) return "🛒 Épicerie & Condiments";
  if (/purée de tomate|puree de tomate/.test(n)) return "🍝 Féculents & Céréales";
  if (/vinaigrette/.test(n)) return "🛒 Épicerie & Condiments";
  if (/noisette|noix de coco/.test(n)) return "🛒 Épicerie & Condiments";
  if (/yaourt|yaoult/.test(n)) return "🧀 Produits Laitiers & Oeufs";
  if (/banane/.test(n)) return "🥦 Fruits & Légumes";
  if (/\bail\b|aïl/.test(n)) return "🥦 Fruits & Légumes";
  if (/échalote|echalote/.test(n)) return "🥦 Fruits & Légumes";
  if (/radis/.test(n)) return "🥦 Fruits & Légumes";
  if (/concombre/.test(n)) return "🥦 Fruits & Légumes";
  if (/comté|comte/.test(n)) return "🧀 Produits Laitiers & Oeufs";
  // Général
  if (/saumon|scampi|crevette|cabillaud|thon|maquereau|saint.?jacque|poisson/.test(n)) return "🐟 Poisson & Fruits de mer";
  if (/poulet|jambon|serrano|bacon|lardons|boeuf|veau|steak|saucisse|chorizo|nuggets|viande|émincés|emincés|dinde/.test(n)) return "🥩 Viande & Charcuterie";
  if (/oeuf|oeufs|crème|creme|beurre|lait|ricotta|mozza|mozzarella|feta|chevre|chèvre|gouda|camembert|parmesan|gruyere|boursin|brie|burrata|emmental|roquefort|fromage|yaourt|cream|alpro/.test(n)) return "🧀 Produits Laitiers & Oeufs";
  if (/pates|pâtes|riz|tagliatelle|spaghetti|penne|lasagne|gnocchi|couscous|ebly|quinoa|blé|ble|lentille|pois.?chiche|pain|baguette|wrap|tortilla|farine|nouille|orzo|crackers|pizza|feuilleté|feuillete|naan/.test(n)) return "🍝 Féculents & Céréales";
  if (/tomate|courgette|aubergine|poivron|oignon|epinard|épinard|brocoli|champignon|salade|crudité|crudites|avocat|chicon|chou|carotte|asperge|haricot|mais|maïs|potimarron|courge|citron|fruit|roquette|pousses|raisin|figue|nectarine|melon|pomme|herbe|basilic|persil|menthe|ciboulette|céleri|celeri|patate|pomme.de.terre/.test(n)) return "🥦 Fruits & Légumes";
  if (/huile|vinaigre|moutarde|pesto|sauce|bouillon|concentré|concentre|passata|lait.de.coco|curry|houmous|nachos|tzatziki|sel |poivre|épice|spice|paprika|curcuma|cumin|cannelle|sucre|sirop|miel|chocolat|cacao|nutella|confiture|levure|extrait/.test(n)) return "🛒 Épicerie & Condiments";
  return "🛒 Épicerie & Condiments";
}


